package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	accounts map[string]float64
	mu       sync.RWMutex
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]float64),
	}
}

func (b *Bank) Deposit(account string, amount float64) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.accounts[account] += amount
}

func (b *Bank) Withdraw(account string, amount float64) bool {
	b.mu.Lock()
	defer b.mu.Unlock()
	if b.accounts[account] >= amount {
		b.accounts[account] -= amount
		return true
	}
	return false
}

func (b *Bank) Balance(account string) float64 {
	b.mu.RLock()
	defer b.mu.RUnlock()
	return b.accounts[account]
}

func main() {
	bank := NewBank()
	var wg sync.WaitGroup

	// Simulate concurrent transactions
	wg.Add(3)
	go func() {
		defer wg.Done()
		bank.Deposit("account1", 100.0)
	}()
	go func() {
		defer wg.Done()
		bank.Withdraw("account1", 50.0)
	}()
	go func() {
		defer wg.Done()
		fmt.Println("Balance:", bank.Balance("account1"))
	}()

	wg.Wait()
	fmt.Println("Final Balance:", bank.Balance("account1"))
}